func (m model) contentLineEstimate() int {
	switch m.detailTab {
	case tabFiles:
		if m.detail != nil {
			return strings.Count(m.detail.Diff, "\n") + len(parseDiffStats(m.detail.Diff).files) + 10
		}
	case tabPlan:
		if m.detail != nil {
			return strings.Count(m.detail.Plan, "\n") + 10
		}
	case tabTranscript:
		return len(m.transcript) * 5
	}
	return 0
}

func RunDashboard(loader *checkpoint.Loader) error {
	m := model{
		loader: loader,
		screen: screenOverview,

package dashboard

import (
	"strings"

	"github.com/charmbracelet/lipgloss"
)

func renderHelp(width, height int) string {
	bindings := []struct{ key, desc string }{
		{"j/k", "Navigate / scroll"},
		{"Enter/l", "Select checkpoint"},
		{"Esc/h", "Go back"},
		{"/", "Filter checkpoints"},
		{"Tab", "Next tab (detail view)"},
		{"Shift+Tab", "Previous tab"},
		{"1-3", "Jump to tab"},
		{"r", "Refresh data"},
		{"?", "Toggle help"},
		{"q", "Quit"},
	}

	var sb strings.Builder
	sb.WriteString(headerStyle.Render("Keyboard Shortcuts"))
	sb.WriteString("\n\n")

	for _, b := range bindings {
		sb.WriteString("  ")
		sb.WriteString(helpKeyStyle.Render(padRight(b.key, 14)))
		sb.WriteString(helpDescStyle.Render(b.desc))
		sb.WriteString("\n")
	}

	sb.WriteString("\n")
	sb.WriteString(dimStyle.Render("  Press ? or Esc to close"))

	content := sb.String()

	boxWidth := 44
	box := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(primary).
		Padding(1, 2).
		Width(boxWidth).
		Render(content)

	return lipgloss.Place(width, height,
		lipgloss.Center, lipgloss.Center,
		box,
	)
}

func padRight(s string, n int) string {
	if len(s) >= n {
		return s
	}
	return s + strings.Repeat(" ", n-len(s))
}

BINARY_NAME=entire-local
VERSION=$(shell git describe --tags --always --dirty 2>/dev/null || echo "dev")
LDFLAGS=-ldflags "-X main.version=${VERSION}"

RED=\033[0;31m
GREEN=\033[0;32m
NC=\033[0m

.PHONY: all build clean test install fmt vet lint check deps help

help:
	@echo "entire-local Makefile"
	@echo ""
	@echo "Targets:"
	@echo "  build    Build the binary"
	@echo "  test     Run tests"
	@echo "  lint     Run golangci-lint"
	@echo "  check    Run fmt, vet, lint"
	@echo "  install  Install to ~/go/bin"
	@echo "  clean    Remove build artifacts"
	@echo "  deps     Download dependencies"
	@echo "  fmt      Format code"
	@echo "  vet      Run go vet"

all: build

build:
	@echo "Building ${BINARY_NAME}..."
	@go build ${LDFLAGS} -o ${BINARY_NAME} .
	@echo "${GREEN}✓${NC} Build complete: ${BINARY_NAME}"

clean:
	@go clean
	@rm -f ${BINARY_NAME}
	@rm -rf dist/
	@rm -f coverage.txt coverage.html

test:
	@echo "Running tests..."
	@go test -v -race -coverprofile=coverage.txt -covermode=atomic ./...
	@echo "${GREEN}✓${NC} Tests complete"

install: build
	@echo "Installing ${BINARY_NAME}..."
	@go install ${LDFLAGS} .
	@echo "${GREEN}✓${NC} Installed to ~/go/bin"

fmt:
	@go fmt ./...

vet:
	@go vet ./...

lint:
	@golangci-lint run

check: fmt vet lint
	@echo "${GREEN}✓${NC} All checks passed"

deps:
	@go mod download
	@go mod tidy

.DEFAULT_GOAL := help
